"use client";

import { useAppDispatch, useAppSelector } from "@/redux/hooks";
import { logout, TUser } from "@/redux/features/auth/authSlice";
import { useRouter, usePathname } from "next/navigation";
import NextLink from "next/link";
import { ChevronDown } from "lucide-react";
import { useState } from "react";
import { useGetNavigationQuery, useGetSiteSettingsQuery } from "@/redux/api/settingsApi";
import { useGetMeQuery } from "@/redux/api/userApi";
import { TNavigationItem, TSiteSettings } from "@/types/settings";

// ─── Layout Component ─────────────────────────────────────────────────────

export default function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const dispatch = useAppDispatch();
  const router = useRouter();
  const pathname = usePathname();
  const user = useAppSelector((state) => state.auth.user) as TUser | null;
  const [openMenu, setOpenMenu] = useState<string | null>(null);
  
  const { data: profileResponse } = useGetMeQuery({}, { skip: !user });
  const profileImg = profileResponse?.data?.user?.profileImg;

  // ── Fetch Dynamic Settings ─────────────────────────────────────────────────
  const { data: navResponse } = useGetNavigationQuery(user?.role, { skip: !user?.role });
  const { data: siteResponse } = useGetSiteSettingsQuery({});

  const handleLogout = () => {
    dispatch(logout());
    router.push("/login");
  };

  // Process dynamic navigation items
  const rawNavItems = (navResponse?.data ?? []) as TNavigationItem[];
  const navItems = rawNavItems.map(item => ({
    ...item,
    active: item.href === pathname || (item.href !== "/dashboard" && pathname.startsWith(item.href))
  }));

  const siteSettings = (siteResponse?.data ?? {
    siteName: "ImmiAccount",
    brandName: "Australian Government",
    departmentName: "Department of Home Affairs",
    footerLinks: [
        { label: "Accessibility", href: "/legal#accessibility" },
        { label: "Copyright", href: "/legal#copyright" },
        { label: "Disclaimer", href: "/legal#disclaimer" },
        { label: "Privacy", href: "/legal#privacy" },
        { label: "Security", href: "/legal#security" },
    ]
  }) as TSiteSettings;


  return (
    <div className="dashboard-root bg-white min-h-screen font-sans text-xs text-gray-700">
      {/* ─── Top Header ─────────────────────────────────────────────── */}
      <header className="bg-[#001a33] h-[55px] flex items-center justify-between px-5 text-white border-b border-white/10">
        <div className="flex items-center gap-2.5">
          <span className="font-bold text-[13px]">{siteSettings.brandName}</span>
          <span className="w-px h-5 bg-white/30" />
          <span className="text-xs">{siteSettings.departmentName}</span>
        </div>

        <div className="flex items-center gap-5">
          <div className="flex items-center gap-2.5">
            {profileImg ? (
              <img
                src={`${process.env.NEXT_PUBLIC_BASE_API || "http://localhost:5000"}${profileImg}`}
                alt="Profile"
                className="w-6 h-6 rounded-full object-cover border border-white/50"
              />
            ) : (
              <div className="w-6 h-6 rounded-full bg-blue-900 border border-white/50 flex items-center justify-center text-[10px] font-bold">
                {user?.email?.charAt(0).toUpperCase() || "U"}
              </div>
            )}
            <span className="text-[11px] font-light text-gray-300">
              {user?.email?.split("@")[0].toUpperCase()},{" "}
              {user?.role?.toUpperCase() || "GUEST"}
            </span>
            <NextLink
              href="/account"
              className="text-white underline text-[11px]"
            >
              Manage Account
            </NextLink>
            <button
              onClick={handleLogout}
              className="text-white underline text-[11px] bg-transparent border-none cursor-pointer"
            >
              Logout
            </button>
          </div>
          <span className="text-2xl font-light ml-5">
            {pathname.startsWith("/payments")
              ? "Online Payments"
              : siteSettings.siteName}
          </span>
        </div>
      </header>

      {/* ─── Navigation Bar ─────────────────────────────────────────── */}
      <nav className="bg-white px-4 flex relative border-b border-gray-300 min-h-[40px]">
        {navItems.map((item) => (
          <div
            key={item.name}
            onMouseEnter={() => item.submenu && setOpenMenu(item.name)}
            onMouseLeave={() => setOpenMenu(null)}
            className="relative"
          >
            <NextLink
              href={item.href}
              className={`px-4 py-2 text-[#2150a0] no-underline text-xs flex items-center gap-1.5 font-normal transition-colors border-b-[3px] ${
                item.active
                  ? "border-[#ff9900] bg-[#f4f7f9]"
                  : openMenu === item.name
                    ? "border-transparent bg-[#f4f7f9]"
                    : "border-transparent hover:bg-gray-50"
              }`}
            >
              {item.name}
              {item.submenu && <ChevronDown size={12} className="opacity-50" />}
            </NextLink>

            {item.submenu && openMenu === item.name && (
              <div className="absolute top-full left-0 bg-white border border-gray-300 min-w-[180px] z-[1000] shadow-lg py-1">
                {item.submenu.map((sub) => (
                  <NextLink
                    key={sub.name}
                    href={sub.href}
                    className="block px-4 py-1.5 text-[#2150a0] no-underline text-[11px] whitespace-nowrap hover:bg-[#e8f1f8] transition-colors"
                  >
                    {sub.name}
                  </NextLink>
                ))}
              </div>
            )}
          </div>
        ))}
      </nav>

      {/* ─── Main Content ───────────────────────────────────────────── */}
      <main className="py-5">
        <div className="w-full">{children}</div>
      </main>

      {/* ─── Footer ──────────────────────────────────────────────────── */}
      <footer className="mt-10 py-5 border-t border-gray-300 text-center text-[11px] text-gray-700">
        <div className="flex justify-center gap-4 mb-2.5">
          {siteSettings.footerLinks.map((item, i) => (
            <span key={item.label} className="flex items-center gap-4">
              {i > 0 && <span className="text-gray-300">|</span>}
              <NextLink href={item.href} className="text-purple-800 underline">
                {item.label}
              </NextLink>
            </span>
          ))}
        </div>
        <p className="text-gray-500">
          &copy; {new Date().getFullYear()} {siteSettings.departmentName}. All rights reserved.
        </p>
      </footer>
    </div>
  );
}

"use client";

import { useGetPaymentsQuery } from "@/redux/api/paymentApi";
import { useGetInvoicesQuery } from "@/redux/api/invoiceApi";
import { useGetAgentsQuery } from "@/redux/api/adminApi";
import { useGetApplicationsQuery } from "@/redux/api/applicationApi";
import { ChevronDown, FileText, CreditCard, PieChart, Activity, DollarSign, Table, User, Search, X } from "lucide-react";
import { useState } from "react";

// ─── Types ──────────────────────────────────────────────────────────────────

interface Agent {
  _id: string;
  name: string;
  email: string;
}

interface Application {
  _id: string;
  trn?: string;
}

interface PaymentRecord {
  _id: string;
  transactionId: string;
  amount: number;
  currency: string;
  status: string;
  gateway: string;
  createdAt: string;
  clientId?: {
    name?: string;
    email?: string;
  };
  applicationId?: {
    _id: string;
    trn?: string;
  };
  agentId?: {
    name?: string;
    email?: string;
  };
}

interface Invoice {
  _id: string;
  invoiceNumber: string;
  createdAt: string;
  amount: number;
  currency: string;
  status: string;
  paymentMethod?: string;
  applicationId?: {
    _id: string;
    trn?: string;
  };
  clientId?: {
    name?: string;
  };
  agentId?: {
    name?: string;
    email?: string;
  };
}

// ─── Sub-components ─────────────────────────────────────────────────────────

const StatCard = ({ label, value, icon: Icon, color }: { label: string; value: string | number; icon: any; color: string }) => (
  <div className="bg-white border border-gray-200 rounded p-4 flex items-center gap-4 shadow-sm">
    <div className={`p-3 rounded-full ${color}`}>
      <Icon size={20} className="text-white" />
    </div>
    <div>
      <p className="text-[11px] text-gray-500 font-medium uppercase tracking-wider">{label}</p>
      <p className="text-xl font-bold text-gray-800">{value}</p>
    </div>
  </div>
);

const TableHeader = ({ columns }: { columns: string[] }) => (
  <thead>
    <tr className="bg-[#00264d] text-white">
      {columns.map((col) => (
        <th
          key={col}
          className="text-left px-3 py-2 font-bold border-r border-white/10 last:border-r-0"
        >
          {col}
        </th>
      ))}
    </tr>
  </thead>
);

// ─── Main Component ─────────────────────────────────────────────────────────

export default function ManagePaymentsPage() {
  const [activeTab, setActiveTab] = useState<"invoices" | "payments" | "stats">("stats");
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedAgent, setSelectedAgent] = useState("");
  const [selectedApp, setSelectedApp] = useState("");

  const { data: agentsData } = useGetAgentsQuery({});
  const { data: appsData } = useGetApplicationsQuery({});

  const commonParams = {
    searchTerm,
    agentId: selectedAgent || undefined,
    applicationId: selectedApp || undefined,
  };

  const { data: invoicesData, isLoading: invLoading } = useGetInvoicesQuery(commonParams);
  const { data: paymentsData, isLoading: payLoading } = useGetPaymentsQuery(commonParams);

  const invoices = (invoicesData?.data?.result || []) as Invoice[];
  const payments = (paymentsData?.data?.result || paymentsData?.data || []) as PaymentRecord[];

  const agents = (agentsData?.data || []) as Agent[];
  const applications = (appsData?.data?.result || appsData?.data || []) as Application[];

  // Calculate some quick stats if API stats not ready
  const totalInvoiced = invoices.reduce((sum, inv) => sum + inv.amount, 0);
  const totalPaid = invoices.filter(inv => inv.status === 'paid').reduce((sum, inv) => sum + inv.amount, 0);

  const invoiceColumns = [
    "Invoice #",
    "Agent / Source",
    "Client",
    "Date",
    "Application",
    "Amount",
    "Status",
  ];

  const paymentColumns = [
    "Transaction ID",
    "Agent",
    "Client",
    "Date",
    "Gateway",
    "Amount",
    "Status"
  ];

  return (
    <div className="px-5 pb-10 font-sans">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-[#00264d] m-0">Payment & Invoice Management</h1>
        <p className="text-gray-500 text-xs mt-1">Monitor all financial transactions across the system.</p>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-300 mb-6 gap-1">
        {[
          { id: "stats", label: "Overview & Stats", icon: PieChart },
          { id: "invoices", label: "Invoice History", icon: FileText },
          { id: "payments", label: "Online Payments", icon: CreditCard },
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex items-center gap-2 px-5 py-2.5 text-xs font-bold transition-all border-b-2 rounded-t cursor-pointer ${
              activeTab === tab.id
                ? "bg-[#2150a0] text-white border-[#2150a0]"
                : "bg-gray-50 text-gray-500 border-transparent hover:bg-gray-100"
            }`}
          >
            <tab.icon size={14} />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Overview Tab */}
      {activeTab === "stats" && (
        <div className="space-y-6 animate-in fade-in duration-300">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <StatCard 
              label="Total Invoiced" 
              value={`$${totalInvoiced.toLocaleString()}`} 
              icon={DollarSign} 
              color="bg-blue-600" 
            />
            <StatCard 
              label="Total Revenue (Paid)" 
              value={`$${totalPaid.toLocaleString()}`} 
              icon={Activity} 
              color="bg-green-600" 
            />
            <StatCard 
              label="Pending Amount" 
              value={`$${(totalInvoiced - totalPaid).toLocaleString()}`} 
              icon={ChevronDown} 
              color="bg-yellow-600" 
            />
            <StatCard 
              label="Total Transactions" 
              value={payments.length + invoices.length} 
              icon={Table} 
              color="bg-purple-600" 
            />
          </div>

          <div className="bg-white border border-gray-200 rounded shadow-sm p-6">
            <h3 className="text-sm font-bold text-gray-700 mb-4">Transaction Performance</h3>
            <div className="h-48 border-b border-l border-gray-100 flex items-end gap-2 px-4">
              {/* Dummy Chart bars representing scale */}
              {[40, 70, 45, 90, 65, 80, 55].map((h, i) => (
                <div key={i} className="flex-1 bg-blue-100 hover:bg-[#2150a0] transition-colors rounded-t cursor-help group relative" style={{ height: `${h}%` }}>
                  <div className="absolute -top-8 left-1/2 -translate-x-1/2 bg-black text-white px-2 py-1 rounded text-[10px] opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                    Day {i+1}: ${h*120}
                  </div>
                </div>
              ))}
            </div>
            <div className="flex justify-between mt-2 text-[10px] text-gray-400 px-4 font-bold uppercase tracking-widest">
              <span>Mon</span>
              <span>Tue</span>
              <span>Wed</span>
              <span>Thu</span>
              <span>Fri</span>
              <span>Sat</span>
              <span>Sun</span>
            </div>
          </div>
        </div>
      )}

      {/* List Tabs */}
      {(activeTab === "invoices" || activeTab === "payments") && (
        <div className="bg-white border border-gray-200 shadow-sm rounded overflow-hidden animate-in slide-in-from-bottom-2 duration-300">
          {/* Filter Bar */}
          <div className="p-4 border-b border-gray-200 bg-gray-50/50 flex flex-wrap gap-4 items-end">
             <div className="flex flex-col gap-1.5">
               <label className="text-[10px] uppercase font-bold text-gray-400 flex items-center gap-1">
                 <User size={10} /> Filter by Agent
               </label>
               <select 
                 value={selectedAgent} 
                 onChange={(e) => setSelectedAgent(e.target.value)}
                 className="border border-gray-300 rounded px-2 py-1.5 text-xs focus:ring-1 focus:ring-blue-500 outline-none w-48 bg-white"
               >
                 <option value="">All Agents</option>
                 {agents.map(agent => (
                   <option key={agent._id} value={agent._id}>{agent.name}</option>
                 ))}
               </select>
             </div>

             <div className="flex flex-col gap-1.5">
               <label className="text-[10px] uppercase font-bold text-gray-400 flex items-center gap-1">
                 <Table size={10} /> Application ID
               </label>
               <select 
                 value={selectedApp} 
                 onChange={(e) => setSelectedApp(e.target.value)}
                 className="border border-gray-300 rounded px-2 py-1.5 text-xs focus:ring-1 focus:ring-blue-500 outline-none w-56 bg-white"
               >
                 <option value="">All Applications</option>
                 {applications.map(app => (
                   <option key={app._id} value={app._id}>{app.trn || app._id.slice(-8).toUpperCase()}</option>
                 ))}
               </select>
             </div>

             <div className="flex flex-col gap-1.5 ml-auto">
               <label className="text-[10px] uppercase font-bold text-gray-400 flex items-center gap-1">
                 <Search size={10} /> Quick Search
               </label>
               <input
                 type="text"
                 value={searchTerm}
                 onChange={(e) => setSearchTerm(e.target.value)}
                 placeholder="Search name, txn, or invoice..."
                 className="border border-gray-300 px-3 py-1.5 text-xs rounded focus:ring-1 focus:ring-blue-500 outline-none w-64 bg-white"
               />
             </div>

             <button 
               onClick={() => { setSelectedAgent(""); setSelectedApp(""); setSearchTerm(""); }}
               className="h-[31px] px-3 text-[10px] font-bold text-gray-500 hover:text-red-600 flex items-center gap-1 bg-white border border-gray-200 rounded"
             >
                <X size={12} /> Reset
             </button>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full border-collapse text-xs">
              <TableHeader columns={activeTab === "invoices" ? invoiceColumns : paymentColumns} />
              <tbody>
                {activeTab === "invoices" ? (
                  invLoading ? (
                    <tr><td colSpan={7} className="p-10 text-center text-gray-400">Loading invoices...</td></tr>
                  ) : invoices.length === 0 ? (
                    <tr><td colSpan={7} className="p-10 text-center text-gray-400">No invoices found.</td></tr>
                  ) : (
                    invoices.map((inv) => (
                      <tr key={inv._id} className="border-b border-gray-100 hover:bg-blue-50/30 transition-colors">
                        <td className="p-3 font-bold text-[#2150a0]">{inv.invoiceNumber}</td>
                        <td className="p-3">
                          <div className="font-bold">{inv.agentId?.name || "Self / System"}</div>
                          <div className="text-[9px] text-gray-400 uppercase tracking-tighter">{inv.paymentMethod || "Direct"}</div>
                        </td>
                        <td className="p-3">{inv.clientId?.name || "N/A"}</td>
                        <td className="p-3 text-gray-500">{new Date(inv.createdAt).toLocaleDateString()}</td>
                        <td className="p-3 font-mono text-[10px] text-gray-400">{inv.applicationId?.trn || inv.applicationId?._id?.slice(-8).toUpperCase() || "N/A"}</td>
                        <td className="p-3 font-bold text-gray-700">${inv.amount.toFixed(2)}</td>
                        <td className="p-3 text-right">
                          <span className={`px-2 py-0.5 rounded-[4px] text-[10px] font-bold uppercase inline-block ${
                            inv.status === 'paid' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'
                          }`}>
                            {inv.status}
                          </span>
                        </td>
                      </tr>
                    ))
                  )
                ) : (
                  payLoading ? (
                    <tr><td colSpan={6} className="p-10 text-center text-gray-400">Loading payments...</td></tr>
                  ) : payments.length === 0 ? (
                    <tr><td colSpan={6} className="p-10 text-center text-gray-400">No online payments found.</td></tr>
                  ) : (
                    payments.map((pay) => (
                      <tr key={pay._id} className="border-b border-gray-100 hover:bg-blue-50/30 transition-colors">
                        <td className="p-3 font-mono text-[11px] text-[#2150a0]">{pay.transactionId}</td>
                        <td className="p-3 font-bold text-gray-600">{pay.agentId?.name || "Direct"}</td>
                        <td className="p-3">
                          <div className="font-bold">{pay.clientId?.name || "Unknown"}</div>
                          <div className="text-[10px] text-gray-400">{pay.clientId?.email}</div>
                        </td>
                        <td className="p-3 text-gray-500">{new Date(pay.createdAt).toLocaleDateString()}</td>
                        <td className="p-3">
                          <span className="px-1.5 py-0.5 bg-gray-100 border border-gray-200 rounded text-[9px] font-bold uppercase text-gray-600">
                            {pay.gateway}
                          </span>
                        </td>
                        <td className="p-3 font-bold text-gray-700">{pay.currency} {pay.amount.toFixed(2)}</td>
                        <td className="p-3 text-right">
                          <span className={`px-2 py-0.5 rounded-[4px] text-[10px] font-bold uppercase inline-block ${
                            pay.status === 'success' ? 'bg-green-100 text-green-700' : 
                            pay.status === 'pending' ? 'bg-yellow-100 text-yellow-700' : 'bg-red-100 text-red-700'
                          }`}>
                            {pay.status}
                          </span>
                        </td>
                      </tr>
                    ))
                  )
                )}
              </tbody>
            </table>
          </div>

          <div className="p-3 border-t border-gray-100 flex justify-between items-center text-[10px] text-gray-500 bg-gray-50/30">
             <span>Showing {activeTab === 'invoices' ? invoices.length : payments.length} transaction entries</span>
             <div className="flex gap-1">
               <button className="px-2 py-1 border border-gray-300 bg-white hover:bg-gray-50 disabled:opacity-50">Prev</button>
               <button className="px-2 py-1 border border-gray-300 bg-white hover:bg-gray-50 disabled:opacity-50">Next</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import NextLink from "next/link";
import { useForm, UseFormRegisterReturn } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as schemas from "@/schemas/profile.schema";
import { useAppDispatch } from "@/redux/hooks";
import { logout } from "@/redux/features/auth/authSlice";
import { useGetMeQuery, useUpdateMyProfileMutation } from "@/redux/api/userApi";
import { useUploadDocumentMutation } from "@/redux/api/documentApi";
import { useRouter } from "next/navigation";
import { useState, useEffect } from "react";
import { useAlert } from "@/components/ui";
import { TAccessRequest } from "@/types/accessRequest";
import { 
  useCreateAccessRequestMutation, 
  useGetMyAccessRequestsQuery,
  useDeleteAccessRequestMutation 
} from "@/redux/api/accessRequestApi";

// Define the tabs
const TABS = [
  "Summary",
  "Account details",
  "Email address",
  "Password",
  "Secret questions",
  "Alert preferences",
  "Request access",
];

export default function ManageAccountPage() {
  const [activeTab, setActiveTab] = useState("Summary");
  const dispatch = useAppDispatch();
  const router = useRouter();
  const { showAlert } = useAlert();

  const { data: profileResponse, isLoading: isProfileLoading } = useGetMeQuery(
    {},
  );
  const [updateProfile] = useUpdateMyProfileMutation();
  const [uploadDoc, { isLoading: isUploadingImage }] =
    useUploadDocumentMutation();
  const [localImgUrl, setLocalImgUrl] = useState<string | null>(null);

  const user = profileResponse?.data?.user;
  const profile = profileResponse?.data?.profile;

  const { data: myRequestsResponse } = useGetMyAccessRequestsQuery({});
  const [createAccessRequest, { isLoading: isCreatingRequest }] = useCreateAccessRequestMutation();
  const [deleteAccessRequest] = useDeleteAccessRequestMutation();
  const [selectedServices, setSelectedServices] = useState<string[]>([]);
  const myRequests = myRequestsResponse?.data || [];

  // Account Details Form
  const accountForm = useForm<schemas.AccountDetailsValues>({
    resolver: zodResolver(schemas.accountDetailsSchema),
  });

  // Email Update Form
  const emailForm = useForm<schemas.EmailUpdateValues>({
    resolver: zodResolver(schemas.emailUpdateSchema),
  });

  // Password Update Form
  const passwordForm = useForm<schemas.PasswordUpdateValues>({
    resolver: zodResolver(schemas.passwordUpdateSchema),
  });

  // Secret Questions Form
  const secretQuestionsForm = useForm<schemas.SecretQuestionsUpdateValues>({
    resolver: zodResolver(schemas.secretQuestionsUpdateSchema),
  });

  useEffect(() => {
    if (profile) {
      accountForm.reset({
        title: profile.title || "",
        givenName: profile.givenNames || user?.name?.split(" ")[0] || "",
        familyName: profile.familyName || user?.name?.split(" ").slice(1).join(" ") || "",
        phone: user?.phone || "",
        mobilePhone: user?.mobilePhone || "",
        address: profile.streetAddress || "",
        city: profile.city || "",
        state: profile.stateProvince || "",
        zip: profile.zipPostalCode || "",
        country: profile.country || "",
        companyName: profile.companyName || "",
        marn: profile.marn || "",
        licenseNumber: profile.licenseNumber || "",
      });
      emailForm.reset({
        email: user?.email || "",
      });
      if (user?.secretQuestions && user?.secretQuestions.length >= 3) {
        secretQuestionsForm.reset({
          q1: user?.secretQuestions[0]?.question || "",
          a1: user?.secretQuestions[0]?.answer || "",
          q2: user?.secretQuestions[1]?.question || "",
          a2: user?.secretQuestions[1]?.answer || "",
          q3: user?.secretQuestions[2]?.question || "",
          a3: user?.secretQuestions[2]?.answer || "",
          q4: user?.secretQuestions[3]?.question || "",
          a4: user?.secretQuestions[3]?.answer || "",
          q5: user?.secretQuestions[4]?.question || "",
          a5: user?.secretQuestions[4]?.answer || "",
        });
      }
    }
  }, [profile, user, accountForm, emailForm, secretQuestionsForm]);

  const onAccountDetailsSubmit = async (data: schemas.AccountDetailsValues) => {
    const targetId = user?.userId || user?._id || user?.id;
    if (!targetId) return;

    try {
      await updateProfile({
        ...data,
        name: `${data.givenName} ${data.familyName}`.trim(),
        givenNames: data.givenName,
        familyName: data.familyName,
        streetAddress: data.address,
        stateProvince: data.state,
        zipPostalCode: data.zip,
        profileImg: localImgUrl || user?.profileImg,
      }).unwrap();
      showAlert({
        type: "success",
        title: "Success",
        message: "Account details updated successfully!",
      });
    } catch (err: unknown) {
      const error = err as { data?: { message?: string }; message?: string };
      showAlert({
        type: "error",
        title: "Update Failed",
        message:
          "Failed to update account details: " +
          (error.data?.message || error.message),
      });
    }
  };

  const onEmailSubmit = async (data: schemas.EmailUpdateValues) => {
    try {
      await updateProfile({ email: data.email }).unwrap();
      showAlert({
        type: "success",
        title: "Verification Sent",
        message: "Email requested for updated. Verification code sent!",
      });
    } catch (err: unknown) {
      const error = err as { data?: { message?: string }; message?: string };
      showAlert({
        type: "error",
        title: "Update Failed",
        message:
          "Failed to update email: " + (error.data?.message || error.message),
      });
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;
    const file = e.target.files[0];
    const formData = new FormData();
    formData.append("file", file);

    try {
      const res = await uploadDoc(formData).unwrap();
      if (res?.data?.url) {
        setLocalImgUrl(res.data.url);
        showAlert({
          type: "success",
          title: "Upload Success",
          message: "Image uploaded. Don't forget to click Save to apply it.",
        });
      }
    } catch (err) {
      console.error(err);
      showAlert({
        type: "error",
        title: "Upload Failed",
        message: "Failed to upload image file.",
      });
    }
  };

  const onPasswordSubmit = async (data: schemas.PasswordUpdateValues) => {
    try {
      await updateProfile({ password: data.newPassword }).unwrap();
      showAlert({
        type: "success",
        title: "Success",
        message: "Password updated successfully!",
      });
      passwordForm.reset();
    } catch (err: unknown) {
      const error = err as { data?: { message?: string }; message?: string };
      showAlert({
        type: "error",
        title: "Update Failed",
        message:
          "Failed to update password: " +
          (error.data?.message || error.message),
      });
    }
  };

  const onSecretQuestionsSubmit = async (
    data: schemas.SecretQuestionsUpdateValues,
  ) => {
    const secretQuestions = [
      { question: data.q1, answer: data.a1 },
      { question: data.q2, answer: data.a2 },
      { question: data.q3, answer: data.a3 },
      ...(data.q4 && data.a4 ? [{ question: data.q4, answer: data.a4 }] : []),
      ...(data.q5 && data.a5 ? [{ question: data.q5, answer: data.a5 }] : []),
    ];

    try {
      await updateProfile({ secretQuestions }).unwrap();
      showAlert({
        type: "success",
        title: "Success",
        message: "Secret questions updated successfully!",
      });
    } catch (err: unknown) {
      const error = err as { data?: { message?: string }; message?: string };
      showAlert({
        type: "error",
        title: "Update Failed",
        message:
          "Failed to update secret questions: " +
          (error.data?.message || error.message),
      });
    }
  };

  const handleServiceToggle = (service: string) => {
    setSelectedServices((prev) =>
      prev.includes(service)
        ? prev.filter((s) => s !== service)
        : [...prev, service],
    );
  };

  const onAccessRequestSubmit = async () => {
    if (selectedServices.length === 0) {
      showAlert({
        type: "error",
        title: "Selection Required",
        message: "Please select at least one service to request.",
      });
      return;
    }

    try {
      for (const serviceName of selectedServices) {
        await createAccessRequest({
          serviceName,
          organisationRegisteredName: profile?.companyName || "-",
        }).unwrap();
      }
      showAlert({
        type: "success",
        title: "Request Submitted",
        message: "Your access requests have been submitted successfully!",
      });
      setSelectedServices([]);
    } catch (err: unknown) {
      const error = err as { data?: { message?: string }; message?: string };
      showAlert({
        type: "error",
        title: "Request Failed",
        message:
          "Failed to submit access requests: " +
          (error.data?.message || error.message),
      });
    }
  };

  const handleRemoveRequest = async (id: string) => {
    try {
      await deleteAccessRequest(id).unwrap();
      showAlert({
        type: "success",
        title: "Request Removed",
        message: "Your access request has been removed successfully.",
      });
    } catch (err: unknown) {
      const error = err as { data?: { message?: string }; message?: string };
      showAlert({
        type: "error",
        title: "Removal Failed",
        message:
          "Failed to remove access request: " +
          (error.data?.message || error.message),
      });
    }
  };

  const handleAlertPreferencesSubmit = async (
    e: React.FormEvent<HTMLFormElement>,
  ) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const alertPassword = formData.get("alertPassword") === "on";
    const alertUserDetails = formData.get("alertUserDetails") === "on";

    try {
      await updateProfile({ alertPassword, alertUserDetails }).unwrap();
      showAlert({
        type: "success",
        title: "Success",
        message: "Alert preferences updated successfully!",
      });
    } catch (err: unknown) {
      const error = err as { data?: { message?: string }; message?: string };
      showAlert({
        type: "error",
        title: "Update Failed",
        message:
          "Failed to update alert preferences: " +
          (error.data?.message || error.message),
      });
    }
  };

  const handleLogout = () => {
    dispatch(logout());
    router.push("/login");
  };

  // Helper for rendering input rows
  const renderInputRow = (
    label: string,
    isRequired: boolean,
    type = "text",
    registerProps: Partial<UseFormRegisterReturn> = {},
    error?: string,
    placeholder = "",
  ) => (
    <div className="flex flex-col mb-2">
      <div className="flex items-center">
        <label className="w-[180px] text-[13px] text-gray-800 font-sans">
          {label} {isRequired && <span className="text-[#c41a1f]">*</span>}
        </label>
        <div className="flex-1 flex items-center">
          {type === "select" ? (
            <select
              {...registerProps}
              className={`border ${error ? "border-[#c41a1f]" : "border-gray-400"} px-1 py-1 w-[280px] text-[13px] rounded-none focus:outline-none`}
            >
              <option></option>
              <option value="Mr">Mr</option>
              <option value="Mrs">Mrs</option>
              <option value="Ms">Ms</option>
              <option value="Miss">Miss</option>
              <option value="Dr">Dr</option>
            </select>
          ) : (
            <input
              type={type}
              {...registerProps}
              placeholder={placeholder}
              className={`border ${error ? "border-[#c41a1f]" : "border-gray-400"} px-2 py-1 w-[280px] text-[13px] rounded-none focus:outline-none`}
            />
          )}
          {isRequired && type !== "password" && type !== "select" && (
            <div className="w-4 h-4 rounded-full bg-[#1b3564] text-white text-[10px] flex items-center justify-center font-bold ml-2 cursor-pointer">
              ?
            </div>
          )}
        </div>
      </div>
      {error && (
        <div className="ml-[180px] text-[#c41a1f] text-[11px] mt-0.5">
          {error}
        </div>
      )}
    </div>
  );

  if (isProfileLoading) {
    return (
      <div className="min-h-screen bg-[#f4f4f4] flex items-center justify-center font-sans">
        <div className="text-[#1b3564] text-lg font-bold">
          Loading account details...
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#f4f4f4] font-sans text-[13px] text-gray-800">
      {/* ─── Top Utility Bar ────────────────────────────────────────────── */}
      <div className="bg-[#1b3564] text-white flex justify-end px-5 py-1 text-[11px] gap-4 tracking-wide font-light border-b border-[#2150a0]">
        <span>{(user?.name || "syed, rahman").toLowerCase()}</span>
        <NextLink href="/dashboard" className="text-white hover:underline">
          Return to Online Lodgement
        </NextLink>
        <button
          onClick={handleLogout}
          className="text-white hover:underline bg-transparent border-none cursor-pointer p-0 font-light"
        >
          Logout
        </button>
      </div>

      {/* ─── Header ──────────────────────────────────────────────────────── */}
      <div className="bg-[#1b3564] h-[75px] flex items-center justify-between px-5 text-white shadow-sm">
        <div className="flex items-center gap-2">
          <div className="flex flex-col">
            <span className="font-bold text-[15px] tracking-wide leading-tight">
              Australian Government
            </span>
            <span className="text-[12px] font-normal leading-tight">
              Department of Home Affairs
            </span>
          </div>
        </div>
        <div className="text-[26px] font-normal tracking-wide text-white">
          Manage my ImmiAccount
        </div>
      </div>

      {/* ─── Tabs Navigation ──────────────────────────────────────────────── */}
      <div className="bg-[#eeeeee] flex border-b border-gray-300 shadow-sm px-1 pt-1">
        {TABS.map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`px-4 py-2 border-t-[3px] border-x border-x-transparent text-[13px] hover:bg-[#e0e0e0] cursor-pointer transition-colors mt-0.5 ${
              activeTab === tab
                ? "bg-white border-t-[#d35400] border-l-gray-300 border-r-gray-300 font-bold border-b-transparent relative z-10 bottom-[-1px]"
                : "bg-transparent border-t-transparent text-gray-700 border-b-transparent hover:border-t-transparent"
            }`}
            style={{
              borderBottomColor: activeTab === tab ? "white" : "transparent",
            }}
          >
            {tab}
          </button>
        ))}
      </div>

      {/* ─── Content Area ─────────────────────────────────────────────────── */}
      <div className="p-4 bg-[#f4f4f4]">
        {/* TAB 1: SUMMARY */}
        {activeTab === "Summary" && (
          <div className="bg-white border border-gray-300 shadow-sm min-h-[500px]">
            <div className="bg-[#1b3564] text-white font-bold text-[13px] px-3 py-1.5">
              Summary
            </div>
            <div className="p-5">
              <h3 className="text-[#1b3564] text-[18px] font-normal mb-2 mt-0">
                My services
              </h3>
              <p className="mb-4 text-[13px]">
                You have access to the following services and can request access
                to additional services from the{" "}
                <a
                  href="#"
                  className="underline text-[#1b3564]"
                  onClick={(e) => {
                    e.preventDefault();
                    setActiveTab("Request access");
                  }}
                >
                  Request access
                </a>{" "}
                tab.
              </p>
              <ul className="list-disc pl-5 mb-8 text-[#1b3564] text-[13px] space-y-1">
                <li>
                  <a href="#" className="underline hover:text-blue-800">
                    Detention Visitor Application
                  </a>
                </li>
                <li>
                  <a href="/payments" className="underline hover:text-blue-800">
                    Manage Payments
                  </a>
                </li>
                <li>
                  <a
                    href="/dashboard"
                    className="underline hover:text-blue-800"
                  >
                    Online Lodgement (Apply for a visa or citizenship including
                    sponsorship and nomination) - Individual
                  </a>
                </li>
                <li>
                  <a href="#" className="underline hover:text-blue-800">
                    LEGENDcom
                  </a>
                </li>
              </ul>

              <div className="border-t border-dashed border-gray-300 mb-6" />

              <div className="grid grid-cols-[200px_1fr] gap-y-1.5 text-[13px]">
                <div className="text-gray-900">Given names</div>
                <div>
                  {user?.name?.split(" ")[0] || "rahman"}{" "}
                  <a
                    href="#"
                    onClick={(e) => {
                      e.preventDefault();
                      setActiveTab("Account details");
                    }}
                    className="text-[#1b3564] underline"
                  >
                    (edit given name)
                  </a>
                </div>

                <div className="text-gray-900">Family name</div>
                <div>
                  {user?.name?.split(" ").slice(1).join(" ") || "syed"}{" "}
                  <a
                    href="#"
                    onClick={(e) => {
                      e.preventDefault();
                      setActiveTab("Account details");
                    }}
                    className="text-[#1b3564] underline"
                  >
                    (edit family name)
                  </a>
                </div>

                <div className="text-gray-900">Email address</div>
                <div>
                  {user?.email || "ghave763@gmail.com"}{" "}
                  <a
                    href="#"
                    onClick={(e) => {
                      e.preventDefault();
                      setActiveTab("Email address");
                    }}
                    className="text-[#1b3564] underline"
                  >
                    (edit email address)
                  </a>
                </div>

                <div className="text-gray-900">Username</div>
                <div className="mb-6">
                  {user?.email || "ghave763@gmail.com"}
                </div>

                {user?.role === "agent" && (
                  <>
                    <div className="text-gray-900">Organisation</div>
                    <div className="mb-6">
                      {profile?.companyName || "N/A"}{" "}
                      <a
                        href="#"
                        onClick={(e) => {
                          e.preventDefault();
                          setActiveTab("Account details");
                        }}
                        className="text-[#1b3564] underline"
                      >
                        (edit organisation)
                      </a>
                    </div>
                  </>
                )}

                <div className="text-gray-900">Alerts</div>
                <div>
                  I will receive account alerts{" "}
                  <a
                    href="#"
                    onClick={(e) => {
                      e.preventDefault();
                      setActiveTab("Alert preferences");
                    }}
                    className="text-[#1b3564] underline"
                  >
                    (change my account alert preferences)
                  </a>
                </div>

                <div className="text-gray-900">Password</div>
                <div>
                  Password saved{" "}
                  <a
                    href="#"
                    onClick={(e) => {
                      e.preventDefault();
                      setActiveTab("Password");
                    }}
                    className="text-[#1b3564] underline"
                  >
                    (change my password)
                  </a>
                </div>



                <div className="text-gray-900">Secret questions</div>
                <div>
                  Secret questions saved{" "}
                  <a
                    href="#"
                    onClick={(e) => {
                      e.preventDefault();
                      setActiveTab("Secret questions");
                    }}
                    className="text-[#1b3564] underline"
                  >
                    (change my secret questions)
                  </a>
                </div>

                <div className="text-gray-900">Terms and conditions</div>
                <div>
                  <a href="#" className="text-[#1b3564] underline">
                    View the ImmiAccount terms and conditions (opens in a new
                    window)
                  </a>
                </div>

                <div className="text-gray-900 mt-1">Delete account</div>
                <div className="mt-1">
                  <a href="#" className="text-[#1b3564] underline">
                    Delete my ImmiAccount
                  </a>
                </div>
              </div>
            </div>
            <div className="bg-[#e5e5e5] px-4 py-3 border-t border-gray-300 mt-6">
              <button
                onClick={() => router.push("/dashboard")}
                className="bg-[#eeeeee] border border-gray-400 px-4 py-1.5 text-[12px] text-gray-800 hover:bg-gray-200"
              >
                Return to Online Lodgement
              </button>
            </div>
          </div>
        )}

        {/* TAB 2: ACCOUNT DETAILS */}
        {activeTab === "Account details" && (
          <form
            onSubmit={accountForm.handleSubmit(onAccountDetailsSubmit)}
            className="bg-white border border-gray-300 shadow-sm min-h-[500px] flex flex-col"
          >
            <div className="bg-[#1b3564] text-white font-bold text-[13px] px-3 py-1.5">
              Update account details
            </div>
            <div className="p-5 flex-1">
              <p className="mb-4 text-[13px] text-black">
                To update your account details enter your given names, family
                name and/or email address and select &apos;Save&apos; to apply
                your changes.
              </p>
              <p className="mb-6 text-[13px] text-black">
                Fields marked <span className="text-[#c41a1f]">*</span> must be
                completed.
              </p>

              <div className="space-y-1 mb-6">
                <div className="flex items-center mb-6">
                  <div className="w-[180px] text-[13px] text-gray-800 font-sans">
                    Username
                  </div>
                  <div className="font-bold">
                    {user?.email || "ghave763@gmail.com"}
                  </div>
                </div>

                <div className="flex items-center mb-6">
                  <div className="w-[180px] text-[13px] text-gray-800 font-sans">
                    Profile Image
                  </div>
                  <div className="flex-1 flex items-center gap-4">
                    {localImgUrl || user?.profileImg ? (
                      <img
                        src={`${process.env.NEXT_PUBLIC_BASE_API || "http://localhost:5000"}${localImgUrl || user?.profileImg}`}
                        alt="Avatar"
                        className="w-14 h-14 rounded-full object-cover border border-gray-300 shadow-sm"
                      />
                    ) : (
                      <div className="w-14 h-14 rounded-full bg-[#1b3564] flex items-center justify-center text-white text-xl font-bold shadow-sm">
                        {user?.email?.charAt(0).toUpperCase() || "U"}
                      </div>
                    )}
                    <label className="cursor-pointer bg-[#eeeeee] border border-gray-400 px-4 py-1.5 text-[12px] text-black hover:bg-gray-200 transition-colors shadow-sm font-medium">
                      {isUploadingImage ? "Uploading..." : "Upload Image"}
                      <input
                        type="file"
                        className="hidden"
                        accept="image/*"
                        onChange={handleImageUpload}
                        disabled={isUploadingImage}
                      />
                    </label>
                  </div>
                </div>

                {renderInputRow(
                  "Title",
                  false,
                  "select",
                  accountForm.register("title"),
                  accountForm.formState.errors.title?.message,
                )}
                {renderInputRow(
                  "Given names",
                  true,
                  "text",
                  accountForm.register("givenName"),
                  accountForm.formState.errors.givenName?.message,
                )}
                {renderInputRow(
                  "Family name",
                  true,
                  "text",
                  accountForm.register("familyName"),
                  accountForm.formState.errors.familyName?.message,
                )}
                {renderInputRow(
                  "Phone",
                  true,
                  "text",
                  accountForm.register("phone"),
                  accountForm.formState.errors.phone?.message,
                )}
                {renderInputRow(
                  "Mobile phone",
                  false,
                  "text",
                  accountForm.register("mobilePhone"),
                  accountForm.formState.errors.mobilePhone?.message,
                )}

                {user?.role === "agent" && (
                  <>
                    {renderInputRow(
                      "Organisation",
                      true,
                      "text",
                      accountForm.register("companyName"),
                      accountForm.formState.errors.companyName?.message,
                    )}
                    {renderInputRow(
                      "MARN",
                      false,
                      "text",
                      accountForm.register("marn"),
                      accountForm.formState.errors.marn?.message,
                    )}
                    {renderInputRow(
                      "License Number",
                      true,
                      "text",
                      accountForm.register("licenseNumber"),
                      accountForm.formState.errors.licenseNumber?.message,
                    )}
                  </>
                )}
              </div>

              <div className="font-bold text-[13px] mb-1">Address details</div>
              <div className="space-y-1">
                <div className="flex items-start mb-1">
                  <label className="w-[180px] text-[13px] text-gray-800 font-sans">
                    Address
                  </label>
                  <div className="flex-1 space-y-1">
                    <input
                      type="text"
                      {...accountForm.register("address")}
                      className={`border ${accountForm.formState.errors.address ? "border-[#c41a1f]" : "border-gray-400"} px-2 py-1 w-[350px] text-[13px] focus:outline-none`}
                    />
                    <input
                      type="text"
                      className="border border-gray-400 px-2 py-1 w-[350px] text-[13px] focus:outline-none block"
                    />
                    <input
                      type="text"
                      className="border border-gray-400 px-2 py-1 w-[350px] text-[13px] focus:outline-none block"
                    />
                  </div>
                </div>
                {renderInputRow(
                  "Suburb/Town",
                  true,
                  "text",
                  accountForm.register("city"),
                  accountForm.formState.errors.city?.message,
                )}

                <div className="flex items-center mb-1">
                  <label className="w-[180px] text-[13px] text-gray-800 font-sans">
                    Country
                  </label>
                  <div className="flex-1">
                    <select
                      {...accountForm.register("country")}
                      className={`border ${accountForm.formState.errors.country ? "border-[#c41a1f]" : "border-gray-400"} px-1 py-1 text-[13px] focus:outline-none w-[280px]`}
                    >
                      <option value=""></option>
                      <option value="Australia">Australia</option>
                      <option value="United States">United States</option>
                      <option value="United Kingdom">United Kingdom</option>
                      <option value="Canada">Canada</option>
                      <option value="Bangladesh">Bangladesh</option>
                    </select>
                  </div>
                </div>

                {renderInputRow(
                  "State",
                  true,
                  "text",
                  accountForm.register("state"),
                  accountForm.formState.errors.state?.message,
                )}
                <div className="flex items-center mb-1">
                  <label className="w-[180px] text-[13px] text-gray-800 font-sans">
                    Postcode/Zip
                  </label>
                  <div className="flex-1">
                    <input
                      type="text"
                      {...accountForm.register("zip")}
                      className={`border ${accountForm.formState.errors.zip ? "border-[#c41a1f]" : "border-gray-400"} px-2 py-1 w-[120px] text-[13px] focus:outline-none block`}
                    />
                  </div>
                </div>
              </div>
            </div>

            <div className="bg-[#e5e5e5] px-4 py-3 border-t border-gray-300 flex justify-between mt-auto">
              <button
                type="button"
                className="bg-[#eeeeee] border border-gray-400 px-4 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors"
              >
                Cancel
              </button>
              <button
                type="submit"
                className="bg-[#eeeeee] border border-gray-400 px-6 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors shadow-sm"
              >
                Save
              </button>
            </div>
          </form>
        )}

        {/* TAB 3: EMAIL ADDRESS */}
        {activeTab === "Email address" && (
          <form
            onSubmit={emailForm.handleSubmit(onEmailSubmit)}
            className="bg-white border border-gray-300 shadow-sm min-h-[500px] flex flex-col"
          >
            <div className="bg-[#1b3564] text-white font-bold text-[13px] px-3 py-1.5">
              Update Email Address
            </div>
            <div className="p-5 flex-1">
              <h2 className="text-[#1b3564] text-[20px] font-normal mb-3 mt-0">
                Update email address for account notifications
              </h2>
              <p className="mb-4 text-[13px] text-black">
                This email address is used for notifications about your account,
                such as password resets. To change the email address used to
                communicate about a visa or citizenship application, select
                &apos;Update us&apos; on the application details page.
              </p>

              <div className="flex mb-8 mt-2">
                <div className="w-[250px] text-[13px] font-bold">
                  Current email address
                </div>
                <div className="text-[13px]">
                  {user?.email || "ghave763@gmail.com"}
                </div>
              </div>

              <p className="mb-6 text-[13px] text-black">
                Enter the new email address to be used for account notifications
                - such as password resets.
              </p>

              <p className="mb-2 text-[13px] text-black">
                Fields marked <span className="text-[#c41a1f]">*</span> must be
                completed.
              </p>

              {renderInputRow(
                "New email address",
                true,
                "email",
                emailForm.register("email"),
                emailForm.formState.errors.email?.message,
              )}

              <p className="mt-8 mb-4 text-[13px] text-black">
                A verification code will be emailed to this new address.
              </p>
              <p className="text-[13px] text-black">
                Select &apos;Send verification code&apos; and enter the
                verification code on the next screen.
              </p>
            </div>

            <div className="bg-[#e5e5e5] px-4 py-3 border-t border-gray-300 flex justify-between mt-auto">
              <button
                type="button"
                className="bg-[#eeeeee] border border-gray-400 px-4 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors"
              >
                Cancel
              </button>
              <button
                type="submit"
                className="bg-[#eeeeee] border border-gray-400 px-4 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors shadow-sm"
              >
                Send verification code
              </button>
            </div>
          </form>
        )}

        {/* TAB 4: PASSWORD */}
        {activeTab === "Password" && (
          <form
            onSubmit={passwordForm.handleSubmit(onPasswordSubmit)}
            className="bg-white border border-gray-300 shadow-sm min-h-[500px] flex flex-col"
          >
            <div className="bg-[#1b3564] text-white font-bold text-[13px] px-3 py-1.5">
              Change Password
            </div>
            <div className="p-5 flex-1">
              <p className="mb-3 text-[13px] text-black">
                Enter the following details to update your password and select
                &apos;Save&apos; to apply your changes:
              </p>
              <p className="mb-6 text-[13px] text-black">
                Fields marked <span className="text-[#c41a1f]">*</span> must be
                completed.
              </p>

              <div className="mb-6">
                {renderInputRow("Current password", true, "password")}
                {renderInputRow(
                  "New password",
                  true,
                  "password",
                  passwordForm.register("newPassword"),
                  passwordForm.formState.errors.newPassword?.message,
                )}
                {renderInputRow(
                  "Confirm new password",
                  true,
                  "password",
                  passwordForm.register("confirmPassword"),
                  passwordForm.formState.errors.confirmPassword?.message,
                )}
              </div>
              <p className="mb-4 text-[13px] text-black">
                Password must be a minimum of fourteen (14) characters{" "}
                <strong>and</strong> include at least one (1) character from
                three (3) of the four (4) groups below:
              </p>
              <ul className="list-disc pl-8 mb-4 text-[13px]">
                <li>lower-case characters (a-z)</li>
                <li>upper-case characters (A-Z)</li>
                <li>digits (0-9)</li>
                <li>
                  punctuation and special characters{" "}
                  {"(-`!@#$%^&*()_+=-\\{}\\.,?/)"}
                </li>
              </ul>
              <p className="mb-6 text-[13px] font-bold">
                Note:{" "}
                <span className="font-normal">
                  You cannot reuse any of your eight (8) previous passwords.
                </span>
              </p>
            </div>

            <div className="bg-[#e5e5e5] px-4 py-3 border-t border-gray-300 flex justify-between mt-auto">
              <button
                type="button"
                className="bg-[#eeeeee] border border-gray-400 px-4 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors"
              >
                Cancel
              </button>
              <button
                type="submit"
                className="bg-[#eeeeee] border border-gray-400 px-6 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors shadow-sm"
              >
                Save
              </button>
            </div>
          </form>
        )}

        {/* TAB 5: SECRET QUESTIONS */}
        {activeTab === "Secret questions" && (
          <form
            onSubmit={secretQuestionsForm.handleSubmit(onSecretQuestionsSubmit)}
            className="bg-white border border-gray-300 shadow-sm min-h-[500px] flex flex-col"
          >
            <div className="bg-[#1b3564] text-white font-bold text-[13px] px-3 py-1.5">
              Secret Questions
            </div>
            <div className="p-5 flex-1">
              <p className="mb-3 text-[13px] text-black">
                Enter the following details to update your secret questions and
                select &apos;Save&apos; to apply your changes:
              </p>
              <p className="mb-6 text-[13px] text-black">
                Fields marked <span className="text-[#c41a1f]">*</span> must be
                completed.
              </p>

              <div className="space-y-6">
                {/* Question 1 */}
                <div>
                  <div className="flex items-center mb-1">
                    <label className="w-[180px] text-[13px] text-gray-800 font-sans">
                      Question 1 <span className="text-[#c41a1f]">*</span>
                    </label>
                    <div className="flex-1">
                      <select
                        {...secretQuestionsForm.register("q1")}
                        className={`border ${secretQuestionsForm.formState.errors.q1 ? "border-[#c41a1f]" : "border-gray-400"} px-1 py-1 w-[280px] text-[13px] rounded-none focus:outline-none`}
                      >
                        <option value="What is your favourite movie?">
                          What is your favourite movie?
                        </option>
                        <option value="What was your first pet's name?">
                          What was your first pet&apos;s name?
                        </option>
                        <option value="In what city were you born?">
                          In what city were you born?
                        </option>
                      </select>
                    </div>
                  </div>
                  {renderInputRow(
                    "Answer 1",
                    true,
                    "text",
                    secretQuestionsForm.register("a1"),
                    secretQuestionsForm.formState.errors.a1?.message,
                  )}
                </div>

                {/* Question 2 */}
                <div>
                  <div className="flex items-center mb-1">
                    <label className="w-[180px] text-[13px] text-gray-800 font-sans">
                      Question 2 <span className="text-[#c41a1f]">*</span>
                    </label>
                    <div className="flex-1">
                      <select
                        {...secretQuestionsForm.register("q2")}
                        className={`border ${secretQuestionsForm.formState.errors.q2 ? "border-[#c41a1f]" : "border-gray-400"} px-1 py-1 w-[280px] text-[13px] rounded-none focus:outline-none`}
                      >
                        <option value="What is the name of your favourite teacher?">
                          What is the name of your favourite teacher?
                        </option>
                        <option value="What is your mother's maiden name?">
                          What is your mother&apos;s maiden name?
                        </option>
                      </select>
                    </div>
                  </div>
                  {renderInputRow(
                    "Answer 2",
                    true,
                    "text",
                    secretQuestionsForm.register("a2"),
                    secretQuestionsForm.formState.errors.a2?.message,
                  )}
                </div>

                {/* Question 3 */}
                <div>
                  <div className="flex items-center mb-1">
                    <label className="w-[180px] text-[13px] text-gray-800 font-sans">
                      Question 3 <span className="text-[#c41a1f]">*</span>
                    </label>
                    <div className="flex-1">
                      <select
                        {...secretQuestionsForm.register("q3")}
                        className={`border ${secretQuestionsForm.formState.errors.q3 ? "border-[#c41a1f]" : "border-gray-400"} px-1 py-1 w-[280px] text-[13px] rounded-none focus:outline-none`}
                      >
                        <option value="Name your favourite holiday destination.">
                          Name your favourite holiday destination.
                        </option>
                        <option value="What is your favourite food?">
                          What is your favourite food?
                        </option>
                      </select>
                    </div>
                  </div>
                  {renderInputRow(
                    "Answer 3",
                    true,
                    "text",
                    secretQuestionsForm.register("a3"),
                    secretQuestionsForm.formState.errors.a3?.message,
                  )}
                </div>

                {/* Question 4 */}
                <div>
                  <div className="flex items-center mb-1">
                    <label className="w-[180px] text-[13px] text-gray-800 font-sans">
                      Question 4
                    </label>
                    <div className="flex-1">
                      <select
                        {...secretQuestionsForm.register("q4")}
                        className={`border ${secretQuestionsForm.formState.errors.q4 ? "border-[#c41a1f]" : "border-gray-400"} px-1 py-1 w-[280px] text-[13px] rounded-none focus:outline-none`}
                      >
                        <option value=""></option>
                        <option value="What is your favourite movie?">
                          What is your favourite movie?
                        </option>
                        <option value="What was your first pet's name?">
                          What was your first pet&apos;s name?
                        </option>
                        <option value="In what city were you born?">
                          In what city were you born?
                        </option>
                        <option value="What is the name of your favourite teacher?">
                          What is the name of your favourite teacher?
                        </option>
                        <option value="What is your mother's maiden name?">
                          What is your mother&apos;s maiden name?
                        </option>
                        <option value="Name your favourite holiday destination.">
                          Name your favourite holiday destination.
                        </option>
                        <option value="What is your favourite food?">
                          What is your favourite food?
                        </option>
                      </select>
                    </div>
                  </div>
                  {renderInputRow(
                    "Answer 4",
                    false,
                    "text",
                    secretQuestionsForm.register("a4"),
                    secretQuestionsForm.formState.errors.a4?.message,
                  )}
                </div>

                {/* Question 5 */}
                <div>
                  <div className="flex items-center mb-1">
                    <label className="w-[180px] text-[13px] text-gray-800 font-sans">
                      Question 5
                    </label>
                    <div className="flex-1">
                      <select
                        {...secretQuestionsForm.register("q5")}
                        className={`border ${secretQuestionsForm.formState.errors.q5 ? "border-[#c41a1f]" : "border-gray-400"} px-1 py-1 w-[280px] text-[13px] rounded-none focus:outline-none`}
                      >
                        <option value=""></option>
                        <option value="What is your favourite movie?">
                          What is your favourite movie?
                        </option>
                        <option value="What was your first pet's name?">
                          What was your first pet&apos;s name?
                        </option>
                        <option value="In what city were you born?">
                          In what city were you born?
                        </option>
                        <option value="What is the name of your favourite teacher?">
                          What is the name of your favourite teacher?
                        </option>
                        <option value="What is your mother's maiden name?">
                          What is your mother&apos;s maiden name?
                        </option>
                        <option value="Name your favourite holiday destination.">
                          Name your favourite holiday destination.
                        </option>
                        <option value="What is your favourite food?">
                          What is your favourite food?
                        </option>
                      </select>
                    </div>
                  </div>
                  {renderInputRow(
                    "Answer 5",
                    false,
                    "text",
                    secretQuestionsForm.register("a5"),
                    secretQuestionsForm.formState.errors.a5?.message,
                  )}
                </div>
              </div>
            </div>

            <div className="bg-[#e5e5e5] px-4 py-3 border-t border-gray-300 flex justify-between mt-auto">
              <button
                type="button"
                className="bg-[#eeeeee] border border-gray-400 px-4 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors"
              >
                Cancel
              </button>
              <button
                type="submit"
                className="bg-[#eeeeee] border border-gray-400 px-6 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors shadow-sm"
              >
                Save
              </button>
            </div>
          </form>
        )}

        {/* TAB 7: ALERT PREFERENCES */}
        {activeTab === "Alert preferences" && (
          <form
            onSubmit={handleAlertPreferencesSubmit}
            className="bg-white border border-gray-300 shadow-sm min-h-[500px] flex flex-col"
          >
            <div className="bg-[#1b3564] text-white font-bold text-[13px] px-3 py-1.5">
              Alert preferences
            </div>
            <div className="p-5 flex-1">
              <p className="mb-4 text-[13px] text-black">
                You will receive alerts for the following events via the email
                address you saved in your ImmiAccount.
              </p>
              <ul className="list-disc pl-8 mb-6 text-[13px]">
                <li>Change secret question and answer</li>
                <li>Delete account</li>
                <li>Forgot login id</li>
                <li>Forgot password</li>

                <li>New browser login</li>
                <li>Verify email</li>
              </ul>

              <p className="mb-4 text-[13px] text-black">
                You can change the following optional alert preferences. Select
                &apos;Save&apos; to apply your changes.
              </p>

              <h3 className="font-bold text-[13px] mb-2 mt-0">
                Optional alerts
              </h3>

              <div className="ml-[180px] space-y-1">
                <div className="flex items-center">
                  <input
                    type="checkbox"
                    id="alertPassword"
                    name="alertPassword"
                    defaultChecked
                    className="mr-2"
                  />
                  <label htmlFor="alertPassword" className="text-[13px]">
                    Change password
                  </label>
                </div>
                <div className="flex items-center">
                  <input
                    type="checkbox"
                    id="alertUserDetails"
                    name="alertUserDetails"
                    defaultChecked
                    className="mr-2"
                  />
                  <label htmlFor="alertUserDetails" className="text-[13px]">
                    User details changed
                  </label>
                </div>
              </div>
            </div>

            <div className="bg-[#e5e5e5] px-4 py-3 border-t border-gray-300 flex justify-between mt-auto">
              <button
                type="button"
                className="bg-[#eeeeee] border border-gray-400 px-4 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors"
              >
                Cancel
              </button>
              <button
                type="submit"
                className="bg-[#eeeeee] border border-gray-400 px-6 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors shadow-sm"
              >
                Save
              </button>
            </div>
          </form>
        )}

        {/* TAB 8: REQUEST ACCESS */}
        {activeTab === "Request access" && (
          <div className="bg-white border border-gray-300 shadow-sm min-h-[500px] flex flex-col">
            <div className="bg-[#1b3564] text-white font-bold text-[13px] px-3 py-1.5">
              Request access
            </div>
            <div className="p-5 flex-1">
              <div className="grid grid-cols-[180px_1fr] gap-y-1 text-[13px] mb-6">
                <div className="font-bold">Name</div>
                <div>{user?.name || "rahman syed"}</div>

                <div className="font-bold">Username</div>
                <div>{user?.email || "ghave763@gmail.com"}</div>
              </div>

              <h3 className="text-[#1b3564] text-[18px] font-normal mb-2 mt-0">
                Requested services
              </h3>
              <div className="overflow-x-auto mb-8 border border-[#cccccc]">
                <table className="w-full text-left text-[12px] border-collapse bg-[#eeeeee]">
                  <thead>
                    <tr className="bg-[#666666] text-white">
                      <th className="p-2 font-bold whitespace-nowrap">
                        Request date
                      </th>
                      <th className="p-2 font-bold">
                        Organisation registered name
                      </th>
                      <th className="p-2 font-bold">Service</th>
                      <th className="p-2 font-bold">Request status</th>
                      <th className="p-2 font-bold text-center">Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {myRequests.length > 0 ? (
                      myRequests.map((req: TAccessRequest) => (
                        <tr key={req._id} className="bg-white border-b border-gray-200">
                          <td className="p-2 whitespace-nowrap">
                            {new Date(req.requestDate).toLocaleDateString("en-GB", {
                              day: "numeric",
                              month: "long",
                              year: "numeric",
                            })}
                          </td>
                          <td className="p-2">{req.organisationRegisteredName || "-"}</td>
                          <td className="p-2">{req.serviceName}</td>
                          <td className="p-2 capitalize">
                            {req.status === "approved"
                              ? `Added on ${new Date(req.updatedAt).toLocaleDateString("en-GB", {
                                  day: "numeric",
                                  month: "long",
                                  year: "numeric",
                                })}`
                              : req.status}
                          </td>
                          <td className="p-2 text-center text-[#1b3564]">
                            {req.status !== "approved" && (
                              <button
                                onClick={() => handleRemoveRequest(req._id)}
                                className="underline hover:text-red-600"
                              >
                                Remove
                              </button>
                            )}
                            {req.status === "approved" && "-"}
                          </td>
                        </tr>
                      ))
                    ) : (
                      <tr className="bg-white">
                        <td colSpan={5} className="p-4 text-center text-gray-500">
                          No access requests found.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>

              <h3 className="text-[#1b3564] text-[18px] font-normal mb-2 mt-0">
                Request additional services
              </h3>
              <p className="mb-4 text-[13px] text-black">
                Fields marked <span className="text-[#c41a1f]">*</span> must be
                completed.
              </p>

              <div className="flex mb-4">
                <div className="w-[300px] text-[13px] font-sans">
                  What type of organisation online services do you need?{" "}
                  <span className="text-[#c41a1f]">*</span>
                </div>
                <div className="flex-1 space-y-1.5 ml-2">
                  {[
                    "Online Lodgement (Apply for a visa or citizenship including sponsorship and nomination)",
                    "Organisation Account Administration",
                    "Visa Entitlement Verification Online (VEVO) for organisations",
                  ].map((service) => (
                    <div key={service} className="flex items-start">
                      <input
                        type="checkbox"
                        id={service}
                        checked={selectedServices.includes(service)}
                        onChange={() => handleServiceToggle(service)}
                        className="mt-[2px] mr-2"
                      />
                      <label htmlFor={service} className="text-[13px]">
                        {service}
                      </label>
                    </div>
                  ))}

                  <p className="text-[13px] font-bold mt-3">
                    Note:{" "}
                    <span className="font-normal">
                      LEGENDcom can be accessed on the{" "}
                      <a
                        href="#"
                        onClick={(e) => {
                          e.preventDefault();
                          setActiveTab("Summary");
                        }}
                        className="text-[#1b3564] underline"
                      >
                        Summary
                      </a>{" "}
                      page (requires the purchase/join of an annual
                      subscription)
                    </span>
                  </p>
                </div>
              </div>
            </div>

            <div className="bg-[#e5e5e5] px-4 py-3 border-t border-gray-300 flex justify-between mt-auto">
              <button
                type="button"
                onClick={() => setSelectedServices([])}
                className="bg-[#eeeeee] border border-gray-400 px-4 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors"
              >
                Cancel
              </button>
              <button
                type="button"
                onClick={onAccessRequestSubmit}
                disabled={isCreatingRequest}
                className="bg-[#eeeeee] border border-gray-400 px-6 py-1 text-[12px] text-black hover:bg-gray-200 transition-colors shadow-sm disabled:opacity-50"
              >
                {isCreatingRequest ? "Submitting..." : "Submit"}
              </button>
            </div>
          </div>
        )}

        {/* OTHER TABS (Placeholders) */}
        {![
          "Summary",
          "Account details",
          "Email address",
          "Password",
          "Secret questions",
          "Alert preferences",
          "Request access",
        ].includes(activeTab) && (
          <div className="bg-white border border-gray-300 shadow-sm min-h-[500px] flex flex-col items-center justify-center">
            <div className="text-gray-400 text-lg">View for {activeTab}</div>
          </div>
        )}
      </div>
    </div>
  );
}
